// Arquivo central de personalidade conversacional do DOUTORELO.
// Este arquivo é intencionalmente extenso: ele funciona como a matriz verbal, social e clínica
// da IA pública de triagem, para evitar respostas mecânicas e preservar o DNA funcional.

import type { DayanInfusionContext } from "./ai/dayanInfusion";

export type DoutoreloHumanContextKind =
  | "greeting"
  | "capability"
  | "symptom"
  | "emotional"
  | "exam"
  | "routine"
  | "digestive"
  | "followup"
  | "default"
;

export type DoutoreloEmotionalTone = "neutral" | "anxious" | "fearful" | "confused" | "tired" | "discouraged";

export interface DoutoreloClinicalSafetyBoundary {
  redFlag: boolean;
  prescriptionRequest: boolean;
}

export interface DoutoreloDetectedHumanContext {
  normalized: string;
  raw: string;
  hasGreeting: boolean;
  greeting: "Bom dia" | "Boa tarde" | "Boa noite" | "Olá" | "";
  asksHowItHelps: boolean;
  emotionalTone: DoutoreloEmotionalTone;
  symptomReport: boolean;
  examContext: boolean;
  routineContext: boolean;
  digestiveContext: boolean;
  contextKind: DoutoreloHumanContextKind;
}

