export const DOUTORELO_COMMUNICATION_CONSTITUTION = {
  identity: "A IA do DOUTORELO deve soar como uma presença humana, consultiva e educada, com raciocínio clínico funcional e limites claros quando necessário.",
  firstResponse: "A primeira resposta precisa conquistar confiança por utilidade, calor humano, objetividade e respeito ao contexto, nunca por disclaimers automáticos.",
  sociability: "Cumprimentos, agradecimentos, medo, confusão e cansaço devem ser reconhecidos naturalmente antes da estrutura técnica.",
  integrativeDna: "A leitura deve conectar corpo, mente, hábitos, sono, alimentação, estresse, movimento, exames, histórico e ambiente sem reduzir a pessoa a um sintoma isolado.",
  limits: "Advertências aparecem somente em limite amarelo ou vermelho: prescrição, dose, diagnóstico individualizado, urgência clínica, risco de vida ou autoagressão.",
  language: "Nunca iniciar respostas comuns com vícios mecânicos como Entendi, Certo ou disclaimers defensivos. Variar aberturas, ritmo, conectivos e perguntas.",
} as const;

function pickStableVariation(options: readonly string[], seed: string, exchangeCount: number): string {
  const chars = Array.from(seed);
  const score = chars.reduce((total, char, position) => total + char.charCodeAt(0) * (position + 1), exchangeCount * 17);
  return options[Math.abs(score) % options.length] ?? options[0] ?? "Vamos olhar isso com cuidado.";
}

export function normalizeHomeChatText(message: string): string {
  return message
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");
}

export function detectDoutoreloHumanContext(message: string): DoutoreloDetectedHumanContext {
  const normalized = normalizeHomeChatText(message);
  const raw = message.toLowerCase();
  const hasGreeting = /\b(oi|ola|olá|bom dia|boa tarde|boa noite|tudo bem|e ai|e aí)\b/.test(raw);
  const greeting = /bom dia/.test(normalized)
    ? "Bom dia"
    : /boa tarde/.test(normalized)
      ? "Boa tarde"
      : /boa noite/.test(normalized)
        ? "Boa noite"
        : hasGreeting
          ? "Olá"
          : "";
  const asksHowItHelps = /\b(como voce pode me ajudar|como vc pode me ajudar|em que voce pode me ajudar|em que vc pode me ajudar|o que voce faz|o que vc faz|como funciona|me ajuda|pode me ajudar)\b/.test(normalized);
  const emotionalTone: DoutoreloEmotionalTone = /\b(medo|assustad|apavorad)\b/.test(normalized)
    ? "fearful"
    : /\b(ansios|nervos|preocupad)\b/.test(normalized)
      ? "anxious"
      : /\b(confus|perdid|nao sei|não sei)\b/.test(raw)
        ? "confused"
        : /\b(cansad|exaust|sem energia)\b/.test(normalized)
          ? "tired"
          : /\b(desanimad|triste|sem esperanca|sem esperança)\b/.test(raw)
            ? "discouraged"
            : "neutral";
  const symptomReport = /\b(dor|sintoma|sono|cans|fadiga|energia|intestin|estomago|reflux|ansiedade|exame|laudo|resultado|febre|tontura|enjoo|mal estar|náusea|nausea)\b/.test(normalized);
  const examContext = /exame|laudo|resultado|pdf|imagem|hemograma|ferritina|vitamina|resson[aâ]ncia|ultrassom/.test(raw);
  const routineContext = /sono|cansa|energia|fadiga|estresse|rotina|h[aá]bito|aliment|treino|exerc[ií]cio/.test(raw);
  const digestiveContext = /intest|digest|est[oô]mago|reflux|gases|abd[oô]men|barriga/.test(raw);
  const contextKind: DoutoreloHumanContextKind = asksHowItHelps && !symptomReport
    ? "capability"
    : emotionalTone !== "neutral"
      ? "emotional"
      : examContext
        ? "exam"
        : digestiveContext
          ? "digestive"
          : routineContext
            ? "routine"
            : hasGreeting && !symptomReport
              ? "greeting"
              : symptomReport
                ? "symptom"
                : "default";

  return { normalized, raw, hasGreeting, greeting, asksHowItHelps, emotionalTone, symptomReport, examContext, routineContext, digestiveContext, contextKind };
}

export function hasDoutoreloClinicalProvocation(message: string, safety?: DoutoreloClinicalSafetyBoundary): boolean {
  if (safety?.redFlag || safety?.prescriptionRequest) return true;
  const context = detectDoutoreloHumanContext(message);
  if (context.symptomReport || context.examContext || context.routineContext || context.digestiveContext) return true;
  if (context.emotionalTone !== "neutral") return true;
  return /\b(remedio|medicamento|suplement|vitamina|hormonio|hormonal|dieta|emagrec|inflama|consulta|medico|doenca|diagnostico|tratamento|pressao|glicemia|cefaleia|enxaqueca)\b/.test(context.normalized)
    || /dor(es)?\s+(de\s+)?cabeca/.test(context.normalized);
}

export function isDoutoreloSimpleSocialMessage(message: string): boolean {
  const context = detectDoutoreloHumanContext(message);
  if (!context.hasGreeting) return false;
  if (hasDoutoreloClinicalProvocation(message)) return false;
  const compact = context.normalized
    .replace(/[^a-z0-9\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  return /^(oi|ola|olá|bom dia|boa tarde|boa noite)$/.test(compact)
    || /^(oi|ola|olá) (bom dia|boa tarde|boa noite)$/.test(compact)
    || /^(bom dia|boa tarde|boa noite) (tudo bem|tudo bom|como vai|como voce esta|como vc esta)$/.test(compact)
    || /^(oi|ola|olá) (tudo bem|tudo bom|como vai)$/.test(compact);
}

export function buildDoutoreloSimpleSocialReply(message: string): string {
  const context = detectDoutoreloHumanContext(message);
  const greeting = context.greeting || "Olá";
  return `${greeting}, em que posso ajudar? Fique à vontade! Estou por aqui.`;
}

export function buildDoutoreloHumanOpening(message: string, exchangeCount: number): string {
  const context = detectDoutoreloHumanContext(message);
  if (exchangeCount > 0) {
    const followupKind = hasDoutoreloClinicalProvocation(message) ? context.contextKind : "followup";
    const safeFollowupBank = followupKind === "greeting" ? DOUTORELO_OPENING_BANK.followup : DOUTORELO_OPENING_BANK[followupKind];
    return pickStableVariation(safeFollowupBank, message, exchangeCount);
  }
  if (context.greeting && context.asksHowItHelps) {
    return `${context.greeting}! ${pickStableVariation(DOUTORELO_OPENING_BANK.capability, message, exchangeCount)}`;
  }
  if (context.greeting && context.contextKind !== "greeting") {
    const base = pickStableVariation(DOUTORELO_OPENING_BANK[context.contextKind], message, exchangeCount);
    return `${context.greeting}! ${base}`;
  }
  return pickStableVariation(DOUTORELO_OPENING_BANK[context.contextKind], message, exchangeCount);
}

export function assertNoMechanicalOpening(answer: string): string {
  const trimmed = answer.trim();
  const forbidden = DOUTORELO_FORBIDDEN_MECHANICAL_OPENERS.find((opener) => trimmed.startsWith(opener));
  if (!forbidden) return answer;
  return trimmed.replace(forbidden, "Vamos olhar isso com cuidado.").trim();
}

export type DoutoreloIntegrativeIntakeProfile = {
  contextQuestion: string;
  lifestyleQuestion: string;
  clinicalBridge: string;
};

const DOUTORELO_MAXIMUM_DAYAN_INFUSION_STYLE = [
  "raciocínio funcional em camadas: sintoma, terreno, rotina, sono, alimentação, intestino, estresse, exames, histórico e ambiente",
  "escuta acolhedora antes da técnica, com perguntas que parecem uma conversa clínica e não um cadastro",
  "uso do corpus Dayan como repertório educativo rastreável, sem copiar falas, sem simular identidade e sem prescrever",
  "retenção por cuidado real: a pessoa deve sentir que está sendo vista, não triada por uma máquina",
] as const;

function buildDayanInfusionSentence(dayanContext?: DayanInfusionContext | null): string {
  if (!dayanContext?.enabled) {
    return "Vou olhar isso pela lógica funcional do DOUTORELO: não só o sintoma isolado, mas o terreno em volta dele, a rotina, o sono, a alimentação, o intestino, o estresse, exames e histórico.";
  }
  const themes = dayanContext.themes.slice(0, 3).join(", ") || "saúde funcional";
  return `Vou usar a lente funcional da base Dayan sobre ${themes}, mas de forma educativa e segura: ela ajuda a organizar melhores perguntas e padrões possíveis, não a fechar diagnóstico ou prescrever conduta.`;
}

function buildIntegrativeIntakeProfile(message: string): DoutoreloIntegrativeIntakeProfile {
  const context = detectDoutoreloHumanContext(message);
  const normalized = context.normalized;
  const hasPain = /\bdor\b|doendo|dolor|pontada|queima|colica|cólica/.test(normalized);
  const hasAbdominalPain = /abdomen|abdominal|barriga|estomago|intestin|baixo ventre|lado direito|lado esquerdo|umbigo/.test(normalized);
  const hasHeadPain = /cabeca|cabeça|enxaqueca|tontura/.test(message.toLowerCase());
  const hasJointOrMusclePain = /joelho|ombro|coluna|costas|musculo|músculo|articula|perna|braco|braço/.test(message.toLowerCase());

  const contextQuestion = hasAbdominalPain || context.digestiveContext
    ? "Você já teve gastrite, refluxo, constipação, diarreia recorrente, intolerância alimentar, problema de vesícula ou alguma outra condição nessa região da dor?"
    : hasHeadPain
      ? "Você costuma ter enxaqueca, sinusite, pressão alta, alteração visual, tensão no pescoço ou alguma condição que venha junto dessa dor?"
      : hasJointOrMusclePain
        ? "Você já teve lesão, inflamação, alteração de coluna, treino recente mais pesado ou alguma doença articular ligada a essa região?"
        : hasPain
          ? "Você já teve algum problema anterior nessa mesma região da dor ou alguma doença que costuma aparecer junto desse sintoma?"
          : context.routineContext
            ? "Isso já aconteceu em outras fases de estresse, mudança de sono, alimentação diferente, treino, trabalho intenso ou alteração hormonal?"
            : "Existe algum histórico seu que possa se conectar com isso, como gastrite, constipação, ansiedade, alteração hormonal, inflamação, alergias, pressão, glicemia ou outro diagnóstico prévio?";

  const lifestyleQuestion = context.digestiveContext || hasAbdominalPain
    ? "Também quero entender sua base: o que você costuma comer num dia normal, como está seu intestino, se dormiu bem nos últimos dias e se percebe relação com estresse ou horários das refeições."
    : context.routineContext
      ? "Me conte como têm sido sono, energia ao acordar, café, açúcar, álcool, treino, telas à noite, estresse e horários das refeições."
      : "E para enxergar o terreno funcional: o que você costuma comer, como anda seu sono, seu intestino, seu nível de estresse, sua hidratação e sua rotina de movimento?";

  return {
    contextQuestion,
    lifestyleQuestion,
    clinicalBridge: "Para eu te acompanhar com mais precisão, me diga sua idade, peso aproximado e altura; não precisa ser exato, é só para calibrar contexto e risco.",
  };
}

function buildMaximumDayanIntegrativeIntake(message: string, exchangeCount: number, dayanContext?: DayanInfusionContext | null): string {
  const profile = buildIntegrativeIntakeProfile(message);
  const styleSeed = pickStableVariation(DOUTORELO_MAXIMUM_DAYAN_INFUSION_STYLE, message, exchangeCount);
  const dayanSentence = buildDayanInfusionSentence(dayanContext);
  return `${dayanSentence}\n\nPara conduzir como uma conversa funcional de verdade, vou combinar ${styleSeed}. ${profile.clinicalBridge} ${profile.contextQuestion} ${profile.lifestyleQuestion}`;
}

export function buildDoutoreloHomeChatAssistantMessage(message: string, safety: DoutoreloClinicalSafetyBoundary, exchangeCount: number, dayanContext?: DayanInfusionContext | null): string {
  const context = detectDoutoreloHumanContext(message);

  if (isDoutoreloSimpleSocialMessage(message) && !safety.redFlag && !safety.prescriptionRequest) {
    return buildDoutoreloSimpleSocialReply(message);
  }

  if (safety.redFlag) {
    const greetingPrefix = context.greeting ? `${context.greeting}. ` : "";
    return `${greetingPrefix}Pelo que você descreveu, isso entra em sinal de alerta e precisa de atendimento de urgência agora.\n\nEnquanto procura ajuda, organize rapidamente: idade, peso aproximado, altura, quando começou, intensidade, sintomas associados, medicamentos em uso, histórico relevante e o que mudou nas últimas horas.`;
  }

  const opening = buildDoutoreloHumanOpening(message, exchangeCount);

  if (safety.prescriptionRequest) {
    const maximumDayanIntake = buildMaximumDayanIntegrativeIntake(message, exchangeCount, dayanContext);
    return assertNoMechanicalOpening(`${opening}\n\nPosso te explicar caminhos, critérios e pontos de atenção, mas não vou escolher dose, remédio ou suplemento por aqui. ${maximumDayanIntake} Com isso, eu monto um resumo claro para você conversar com um profissional habilitado.`);
  }

  if (context.asksHowItHelps && !hasDoutoreloClinicalProvocation(message, safety)) {
    return assertNoMechanicalOpening(`${opening}\n\nPosso te ajudar a organizar sintomas, exames, rotina ou dúvidas de saúde com calma. Me conte o que você quer entender primeiro.`);
  }

  if (!hasDoutoreloClinicalProvocation(message, safety)) {
    return assertNoMechanicalOpening(`${opening}\n\nFique à vontade para me contar o que você quer entender ou o que está sentindo. Estou por aqui.`);
  }

  const maximumDayanIntake = buildMaximumDayanIntegrativeIntake(message, exchangeCount, dayanContext);

  if (context.examContext) {
    return assertNoMechanicalOpening(`${opening}\n\nMe envie o nome do exame, a data e os valores que vieram alterados. ${maximumDayanIntake} Eu separo o que é achado isolado, padrão possível, sinal de atenção e pergunta útil para levar adiante.`);
  }

  if (context.routineContext) {
    return assertNoMechanicalOpening(`${opening}\n\n${maximumDayanIntake} Não precisa responder perfeito; pode mandar em texto livre que eu organizo o raciocínio por camadas.`);
  }

  if (context.digestiveContext) {
    return assertNoMechanicalOpening(`${opening}\n\n${maximumDayanIntake} A partir daí eu separo pistas úteis de ruído, com cuidado para não transformar hipótese em diagnóstico.`);
  }

  return assertNoMechanicalOpening(`${opening}\n\n${maximumDayanIntake} Pode escrever do seu jeito; eu organizo o raciocínio e sigo com perguntas melhores.`);
}
